import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Text3D, Float, PerspectiveCamera, Environment, Sparkles, MeshReflectorMaterial } from '@react-three/drei';
import { EffectComposer, Bloom, DepthOfField } from '@react-three/postprocessing';
import * as THREE from 'three';
import { getRoomTypes } from '../api/rooms';

// 3D Floating Room Card Component
function FloatingRoomCard({ position, type, style, formatPrice, getRoomDescription, index }) {
  const meshRef = useRef();
  const [hovered, setHovered] = useState(false);

  useFrame((state) => {
    if (meshRef.current) {
      // Gentle floating animation
      meshRef.current.position.y = position[1] + Math.sin(state.clock.elapsedTime * 0.5 + index) * 0.1;
      meshRef.current.rotation.z = Math.sin(state.clock.elapsedTime * 0.3 + index) * 0.03;

      // Hover effect scale
      if (hovered) {
        meshRef.current.scale.lerp(new THREE.Vector3(1.05, 1.05, 1.05), 0.1);
      } else {
        meshRef.current.scale.lerp(new THREE.Vector3(1, 1, 1), 0.1);
      }
    }
  });

  return (
    <group position={position} ref={meshRef}>
      {/* 3D Card Body */}
      <mesh
        onPointerOver={() => setHovered(true)}
        onPointerOut={() => setHovered(false)}
        castShadow
        receiveShadow
      >
        <boxGeometry args={[3.5, 4, 0.2]} />
        <meshStandardMaterial color={style.bg} metalness={0.7} roughness={0.3} emissive={hovered ? style.accent : '#000000'} emissiveIntensity={hovered ? 0.2 : 0} />
      </mesh>

      {/* Card Frame */}
      <mesh position={[0, 0, 0.11]}>
        <boxGeometry args={[3.7, 4.2, 0.05]} />
        <meshStandardMaterial color={style.accent} metalness={0.9} roughness={0.2} />
      </mesh>

      {/* Icon on card */}
      <Text3D
        font="/fonts/helvetiker_regular.typeface.json"
        size={0.8}
        height={0.05}
        position={[0, 1.2, 0.12]}
      >
        {style.icon}
        <meshStandardMaterial color={style.accent} metalness={0.8} />
      </Text3D>

      {/* Room Name */}
      <Text3D
        font="/fonts/helvetiker_regular.typeface.json"
        size={0.25}
        height={0.03}
        position={[-1.2, 0.5, 0.12]}
      >
        {type.name}
        <meshStandardMaterial color="#ffffff" metalness={0.5} />
      </Text3D>

      {/* Price */}
      <Text3D
        font="/fonts/helvetiker_regular.typeface.json"
        size={0.2}
        height={0.03}
        position={[-1.5, -0.8, 0.12]}
      >
        {formatPrice(type.base_price)}
        <meshStandardMaterial color="#ffd700" metalness={0.8} />
      </Text3D>
    </group>
  );
}

// 3D Scene Background
function SceneBackground() {
  const { scene } = useThree();

  useEffect(() => {
    scene.background = new THREE.Color(0x0a1e3d);
    scene.fog = new THREE.FogExp2(0x0a1e3d, 0.008);
  }, [scene]);

  return (
    <>
      {/* Floating Particles */}
      <Sparkles count={500} scale={20} size={0.5} speed={0.3} opacity={0.5} color="#c9a84c" />

      {/* Ambient Light */}
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1} />
      <pointLight position={[-10, 5, -5]} intensity={0.5} color="#c9a84c" />
      <directionalLight position={[5, 10, 7]} intensity={1} castShadow />

      {/* Rotating Light Orbs */}
      <Float speed={1} rotationIntensity={1} floatIntensity={2}>
        <mesh position={[5, 3, -8]}>
          <sphereGeometry args={[0.5, 32, 32]} />
          <meshStandardMaterial color="#c9a84c" emissive="#c9a84c" emissiveIntensity={0.5} />
        </mesh>
      </Float>

      <Float speed={1.5} rotationIntensity={1} floatIntensity={1.5}>
        <mesh position={[-4, 2, -7]}>
          <sphereGeometry args={[0.3, 32, 32]} />
          <meshStandardMaterial color="#1e5fa8" emissive="#1e5fa8" emissiveIntensity={0.3} />
        </mesh>
      </Float>

      {/* Reflective Floor */}
      <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -3, 0]} receiveShadow>
        <planeGeometry args={[30, 30]} />
        <MeshReflectorMaterial
          blur={[300, 100]}
          resolution={2048}
          mixBlur={1}
          mixStrength={40}
          roughness={1}
          depthScale={1.2}
          minDepthThreshold={0.4}
          maxDepthThreshold={1.4}
          color="#0a1e3d"
          metalness={0.8}
        />
      </mesh>
    </>
  );
}

// 3D Hero Section
function Hero3D() {
  const groupRef = useRef();

  useFrame((state) => {
    if (groupRef.current) {
      groupRef.current.rotation.y = Math.sin(state.clock.elapsedTime * 0.1) * 0.1;
    }
  });

  return (
    <group ref={groupRef}>
      {/* Central Rotating Structure */}
      <Float speed={0.5} rotationIntensity={0.5} floatIntensity={1}>
        <mesh position={[0, 0, 0]} castShadow>
          <torusKnotGeometry args={[1.5, 0.3, 128, 16, 3, 4]} />
          <meshStandardMaterial color="#c9a84c" metalness={0.9} roughness={0.1} emissive="#c9a84c" emissiveIntensity={0.3} />
        </mesh>
      </Float>

      {/* Floating Rings */}
      {[1, 2, 3].map((i) => (
        <Float key={i} speed={0.8 - i * 0.2} rotationIntensity={0.3} floatIntensity={0.5}>
          <mesh rotation={[Math.PI / 2, 0, 0]} position={[0, i * 0.8 - 1, 0]}>
            <torusGeometry args={[2 + i * 0.5, 0.05, 64, 200]} />
            <meshStandardMaterial color={i === 2 ? "#c9a84c" : "#1e5fa8"} metalness={0.8} emissiveIntensity={0.2} />
          </mesh>
        </Float>
      ))}

      {/* Particles around hero */}
      <Sparkles count={200} scale={8} size={0.2} speed={0.5} opacity={0.6} color="#ffffff" />
    </group>
  );
}

// Main 3D HomePage Component
export default function HomePage() {
  const [roomTypes, setRoomTypes] = useState([]);
  const [typesLoading, setTypesLoading] = useState(true);
  const [roomTypeImages, setRoomTypeImages] = useState({});
  const [show3D, setShow3D] = useState(true);

  useEffect(() => {
    const fetchRoomTypes = async () => {
      try {
        const { data } = await getRoomTypes();
        const types = data.results || data;
        setRoomTypes(types);

        const images = {};
        types.forEach(type => {
          const name = type.name.toLowerCase();
          if (name === 'standard') {
            images[type.id] = { bg: '#dbeafe', accent: '#1e5fa8', icon: '🛏️' };
          } else if (name === 'deluxe') {
            images[type.id] = { bg: '#fef3c7', accent: '#92400e', icon: '✨' };
          } else if (name === 'suite') {
            images[type.id] = { bg: '#f0fdf4', accent: '#065f46', icon: '👑' };
          } else {
            images[type.id] = { bg: '#f3e8ff', accent: '#7c3aed', icon: '🏨' };
          }
        });
        setRoomTypeImages(images);
      } catch (error) {
        console.error('Error fetching room types:', error);
      } finally {
        setTypesLoading(false);
      }
    };
    fetchRoomTypes();
  }, []);

  const formatPrice = (price) => `₱${Number(price).toLocaleString()}/night`;

  const getRoomDescription = (typeName) => {
    const name = typeName.toLowerCase();
    if (name === 'standard') {
      return 'Comfortable and well-appointed rooms with all essential amenities for a perfect stay.';
    } else if (name === 'deluxe') {
      return 'Spacious rooms with premium furnishings, enhanced amenities, and stunning views.';
    } else if (name === 'suite') {
      return 'The pinnacle of luxury — expansive suites with separate living areas and exclusive perks.';
    } else {
      return `Experience our luxurious ${typeName} rooms with premium amenities and exceptional service.`;
    }
  };

  return (
    <div>
      {/* 3D Hero Section */}
      <section style={{
        height: '100vh',
        position: 'relative',
        overflow: 'hidden',
      }}>
        <Canvas
          shadows
          camera={{ position: [0, 2, 8], fov: 50 }}
          style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}
        >
          <EffectComposer>
            <Bloom intensity={0.5} luminanceThreshold={0.2} luminanceSmoothing={0.9} />
            <DepthOfField focusDistance={0.01} focalLength={0.02} bokehScale={2} />
          </EffectComposer>

          <PerspectiveCamera makeDefault position={[0, 2, 8]} />
          <OrbitControls 
            enableZoom={false} 
            enablePan={false}
            autoRotate
            autoRotateSpeed={0.5}
            enableDamping
          />

          <SceneBackground />
          <Hero3D />

          <Environment preset="night" />
        </Canvas>

        {/* Overlay Text */}
        <div style={{
          position: 'absolute',
          bottom: '15%',
          left: 0,
          right: 0,
          textAlign: 'center',
          zIndex: 10,
          pointerEvents: 'none',
        }}>
          <div style={{
            fontSize: '0.75rem',
            letterSpacing: '0.25em',
            color: '#c9a84c',
            textTransform: 'uppercase',
            marginBottom: 20,
            fontWeight: 600,
            textShadow: '0 0 20px rgba(0,0,0,0.5)'
          }}>
            Welcome to Grand Azure
          </div>
          <h1 style={{
            fontFamily: 'var(--font-display)',
            fontSize: 'clamp(3rem, 7vw, 5.5rem)',
            fontWeight: 300,
            color: 'white',
            lineHeight: 1.1,
            marginBottom: 20,
            textShadow: '0 0 30px rgba(0,0,0,0.3)'
          }}>
            Where Luxury<br /><em style={{ fontStyle: 'italic', color: '#ffd700' }}>Meets Comfort</em>
          </h1>
          <button
            onClick={() => document.getElementById('rooms-section')?.scrollIntoView({ behavior: 'smooth' })}
            style={{
              marginTop: 30,
              padding: '14px 32px',
              background: 'linear-gradient(135deg, #c9a84c 0%, #b8923e 100%)',
              border: 'none',
              borderRadius: 50,
              color: 'white',
              fontWeight: 600,
              cursor: 'pointer',
              transition: 'transform 0.3s',
              pointerEvents: 'auto'
            }}
            onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.05)'}
            onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}
          >
            Explore Our World
          </button>
        </div>

        {/* 3D Toggle Button */}
        <button
          onClick={() => setShow3D(!show3D)}
          style={{
            position: 'absolute',
            bottom: 20,
            right: 20,
            zIndex: 20,
            padding: '10px 20px',
            background: 'rgba(0,0,0,0.7)',
            border: '1px solid #c9a84c',
            borderRadius: 8,
            color: '#c9a84c',
            cursor: 'pointer',
            backdropFilter: 'blur(10px)',
            fontSize: '0.8rem'
          }}
        >
          {show3D ? '2D Mode' : '3D Mode'}
        </button>
      </section>

      {/* Features Section (unchanged but with subtle animations) */}
      <section className="section" style={{ background: 'white', position: 'relative', zIndex: 5 }}>
        <div className="container" style={{ textAlign: 'center' }}>
          <div style={{ fontSize: '0.75rem', letterSpacing: '0.2em', color: 'var(--blue)', textTransform: 'uppercase', marginBottom: 12, fontWeight: 600 }}>Why Choose Us</div>
          <h2 className="section-title" style={{ marginBottom: 48 }}>The Grand Azure Experience</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: 32 }}>
            {[
              { icon: '🌊', title: 'Breathtaking Views', desc: 'Wake up to panoramic cityscapes and natural beauty from every room.' },
              { icon: '🍽️', title: 'Fine Dining', desc: 'World-class cuisine crafted by expert chefs using fresh local ingredients.' },
              { icon: '🧖', title: 'Wellness & Spa', desc: 'Rejuvenate your body and mind with our premium wellness facilities.' },
              { icon: '🏊', title: 'Infinity Pool', desc: 'Dive into luxury with our stunning rooftop infinity pool experience.' },
              { icon: '🔒', title: 'Secure Booking', desc: 'Book with confidence. Your reservation is guaranteed and protected.' },
              { icon: '💳', title: 'Pay at Hotel', desc: 'No upfront payment required. Simply pay upon arrival at check-in.' },
            ].map(({ icon, title, desc }, idx) => (
              <div key={title} style={{ 
                padding: '32px 24px', 
                borderRadius: 16, 
                border: '1px solid var(--gray-100)', 
                textAlign: 'center', 
                transition: 'all 0.3s',
                transform: 'translateY(0)',
                animation: `fadeUp 0.6s ease ${idx * 0.1}s forwards`,
                opacity: 0
              }}
                onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-10px)'; e.currentTarget.style.borderColor = 'var(--blue)'; e.currentTarget.style.boxShadow = 'var(--shadow-md)'; }}
                onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.borderColor = 'var(--gray-100)'; e.currentTarget.style.boxShadow = 'none'; }}
              >
                <div style={{ fontSize: '2.5rem', marginBottom: 16 }}>{icon}</div>
                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', color: 'var(--navy)', marginBottom: 8 }}>{title}</h3>
                <p style={{ color: 'var(--gray-600)', fontSize: '0.9rem', lineHeight: 1.7 }}>{desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* 3D Room Types Section */}
      <section id="rooms-section" className="section" style={{ background: 'var(--cream)', position: 'relative', minHeight: '100vh' }}>
        <div className="container">
          <div style={{ textAlign: 'center', marginBottom: 48 }}>
            <div style={{ fontSize: '0.75rem', letterSpacing: '0.2em', color: 'var(--blue)', textTransform: 'uppercase', marginBottom: 12, fontWeight: 600 }}>Accommodations</div>
            <h2 className="section-title">Our Room Categories</h2>
            <p className="section-subtitle">Experience luxury in 3D</p>
          </div>

          {typesLoading ? (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 24 }}>
              {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height: 400, borderRadius: 16 }} />)}
            </div>
          ) : (
            show3D ? (
              <div style={{ height: '600px', position: 'relative' }}>
                <Canvas
                  camera={{ position: [0, 2, 12], fov: 45 }}
                  style={{ borderRadius: 24, background: 'linear-gradient(180deg, #0a1e3d 0%, #1a3a5c 100%)' }}
                >
                  <ambientLight intensity={0.5} />
                  <pointLight position={[10, 10, 10]} intensity={1} />
                  <pointLight position={[-10, 5, 5]} intensity={0.5} color="#c9a84c" />

                  <OrbitControls 
                    enableZoom={true}
                    enablePan={true}
                    autoRotate
                    autoRotateSpeed={0.8}
                    enableDamping
                  />

                  {roomTypes.map((type, index) => {
                    const style = roomTypeImages[type.id] || { bg: '#f3e8ff', accent: '#7c3aed', icon: '🏨' };
                    const angle = (index / roomTypes.length) * Math.PI * 2;
                    const radius = 5;
                    const x = Math.cos(angle) * radius;
                    const z = Math.sin(angle) * radius;

                    return (
                      <FloatingRoomCard
                        key={type.id}
                        position={[x, 0, z]}
                        type={type}
                        style={style}
                        formatPrice={formatPrice}
                        getRoomDescription={getRoomDescription}
                        index={index}
                      />
                    );
                  })}

                  <Sparkles count={300} scale={15} size={0.3} speed={0.4} opacity={0.4} color="#c9a84c" />
                  <Environment preset="city" />
                </Canvas>

                <div style={{
                  position: 'absolute',
                  bottom: 20,
                  left: 0,
                  right: 0,
                  textAlign: 'center',
                  color: 'white',
                  fontSize: '0.8rem',
                  background: 'rgba(0,0,0,0.6)',
                  padding: '8px',
                  borderRadius: 8,
                  margin: '0 auto',
                  width: 'fit-content',
                  backdropFilter: 'blur(5px)'
                }}>
                  🖱️ Drag to rotate • Scroll to zoom • Hover over rooms
                </div>
              </div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: 24 }}>
                {roomTypes.map(type => {
                  const style = roomTypeImages[type.id] || { bg: '#f3e8ff', accent: '#7c3aed', icon: '🏨' };
                  return (
                    <div key={type.id} style={{ background: 'white', borderRadius: 16, overflow: 'hidden', boxShadow: 'var(--shadow-sm)', border: '1px solid var(--gray-100)', transition: 'all 0.3s' }}
                      onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-6px)'; e.currentTarget.style.boxShadow = 'var(--shadow-lg)'; }}
                      onMouseLeave={e => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.boxShadow = 'var(--shadow-sm)'; }}
                    >
                      <div style={{ height: 180, background: style.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 8 }}>
                        <span style={{ fontSize: '3rem' }}>{style.icon}</span>
                        <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', color: style.accent, opacity: 0.5, textTransform: 'capitalize' }}>
                          {type.name}
                        </span>
                      </div>
                      <div style={{ padding: 24 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: 10 }}>
                          <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', color: 'var(--navy)', textTransform: 'capitalize' }}>
                            {type.name} Room
                          </h3>
                          <span style={{ fontSize: '0.78rem', color: 'var(--blue)', fontWeight: 600, background: style.bg, padding: '4px 10px', borderRadius: 99 }}>
                            {formatPrice(type.base_price)}
                          </span>
                        </div>
                        <p style={{ color: 'var(--gray-600)', fontSize: '0.88rem', lineHeight: 1.7, marginBottom: 16 }}>
                          {type.description || getRoomDescription(type.name)}
                        </p>
                        <div style={{ marginBottom: 16 }}>
                          <span style={{ fontSize: '0.75rem', color: 'var(--gray-500)' }}>
                            👥 Up to {type.capacity} guests
                          </span>
                          {type.amenities && type.amenities.length > 0 && (
                            <div style={{ marginTop: 8, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                              {type.amenities.slice(0, 3).map(amenity => (
                                <span key={amenity} style={{ fontSize: '0.7rem', background: 'var(--gray-100)', padding: '2px 8px', borderRadius: 99, color: 'var(--gray-600)' }}>
                                  {amenity}
                                </span>
                              ))}
                              {type.amenities.length > 3 && (
                                <span style={{ fontSize: '0.7rem', color: 'var(--gray-500)' }}>+{type.amenities.length - 3} more</span>
                              )}
                            </div>
                          )}
                        </div>
                        <Link to="/rooms" style={{ color: 'var(--blue)', fontSize: '0.88rem', fontWeight: 600, display: 'flex', alignItems: 'center', gap: 4 }}>
                          View details →
                        </Link>
                      </div>
                    </div>
                  );
                })}
              </div>
            )
          )}
        </div>
      </section>

      {/* CTA Section */}
      <section style={{ background: 'linear-gradient(135deg, var(--navy) 0%, var(--navy-mid) 100%)', padding: '80px 0', position: 'relative', overflow: 'hidden' }}>
        <div className="container" style={{ textAlign: 'center', position: 'relative', zIndex: 2 }}>
          <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '2.8rem', fontWeight: 300, color: 'white', marginBottom: 16 }}>
            Ready for Your Stay?
          </h2>
          <p style={{ color: 'rgba(255,255,255,0.65)', fontSize: '1rem', marginBottom: 32 }}>Book directly and enjoy our best available rates.</p>
          <div style={{ display: 'flex', gap: 16, justifyContent: 'center' }}>
            <Link to="/rooms" className="btn btn-gold" style={{ fontSize: '0.95rem', padding: '14px 32px', transition: 'transform 0.3s' }}
              onMouseEnter={e => e.currentTarget.style.transform = 'scale(1.05)'}
              onMouseLeave={e => e.currentTarget.style.transform = 'scale(1)'}>
              Browse Our Rooms
            </Link>
          </div>
        </div>

        {/* Animated background particles */}
        <div style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: 'radial-gradient(circle at 20% 50%, rgba(201,168,76,0.1) 0%, transparent 50%)',
          pointerEvents: 'none'
        }} />
      </section>

      <style jsx>{`
        @keyframes fadeUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
      `}</style>
    </div>
  );
}
